import{_ as n,o as t,c as s,ak as l}from"./chunks/framework.DwHlt8HN.js";const c=JSON.parse('{"title":"排序算法分类与复杂度总览","description":"","frontmatter":{},"headers":[],"relativePath":"cs/algorithm/sort-overview.md","filePath":"cs/algorithm/sort-overview.md","lastUpdated":1774353797000}'),e={name:"cs/algorithm/sort-overview.md"};function i(d,a,r,p,h,o){return t(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="排序算法分类与复杂度总览" tabindex="-1">排序算法分类与复杂度总览 <a class="header-anchor" href="#排序算法分类与复杂度总览" aria-label="Permalink to “排序算法分类与复杂度总览”">​</a></h1><h2 id="排序-程序员的基本功" tabindex="-1">排序：程序员的基本功 <a class="header-anchor" href="#排序-程序员的基本功" aria-label="Permalink to “排序：程序员的基本功”">​</a></h2><p>排序是算法中最基础的问题，也是面试中出现频率最高的话题之一。</p><p>但排序算法种类繁多：冒泡、选择、插入、归并、快速、堆排、计数、桶排、基数……</p><p>它们有什么区别？什么时候该用哪个？</p><p>今天，让我们系统性地梳理排序算法家族。</p><h2 id="排序算法全景图" tabindex="-1">排序算法全景图 <a class="header-anchor" href="#排序算法全景图" aria-label="Permalink to “排序算法全景图”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>排序算法</span></span>
<span class="line"><span>├── 比较排序</span></span>
<span class="line"><span>│   ├── O(n²) 类</span></span>
<span class="line"><span>│   │   ├── 冒泡排序</span></span>
<span class="line"><span>│   │   ├── 选择排序</span></span>
<span class="line"><span>│   │   └── 插入排序</span></span>
<span class="line"><span>│   ├── O(n log n) 类</span></span>
<span class="line"><span>│   │   ├── 归并排序</span></span>
<span class="line"><span>│   │   ├── 快速排序</span></span>
<span class="line"><span>│   │   └── 堆排序</span></span>
<span class="line"><span>│   └── 其他</span></span>
<span class="line"><span>│       └── 希尔排序</span></span>
<span class="line"><span>└── 非比较排序</span></span>
<span class="line"><span>    ├── 计数排序</span></span>
<span class="line"><span>    ├── 桶排序</span></span>
<span class="line"><span>    └── 基数排序</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><h2 id="复杂度总览" tabindex="-1">复杂度总览 <a class="header-anchor" href="#复杂度总览" aria-label="Permalink to “复杂度总览”">​</a></h2><table tabindex="0"><thead><tr><th>排序算法</th><th>平均时间</th><th>最坏时间</th><th>空间</th><th>稳定性</th></tr></thead><tbody><tr><td>冒泡排序</td><td>O(n²)</td><td>O(n²)</td><td>O(1)</td><td>稳定</td></tr><tr><td>选择排序</td><td>O(n²)</td><td>O(n²)</td><td>O(1)</td><td>不稳定</td></tr><tr><td>插入排序</td><td>O(n²)</td><td>O(n²)</td><td>O(1)</td><td>稳定</td></tr><tr><td>希尔排序</td><td>O(n^1.3)</td><td>O(n²)</td><td>O(1)</td><td>不稳定</td></tr><tr><td>归并排序</td><td>O(n log n)</td><td>O(n log n)</td><td>O(n)</td><td>稳定</td></tr><tr><td>快速排序</td><td>O(n log n)</td><td>O(n²)</td><td>O(log n)</td><td>不稳定</td></tr><tr><td>堆排序</td><td>O(n log n)</td><td>O(n log n)</td><td>O(1)</td><td>不稳定</td></tr><tr><td>计数排序</td><td>O(n + k)</td><td>O(n + k)</td><td>O(k)</td><td>稳定</td></tr><tr><td>桶排序</td><td>O(n + k)</td><td>O(n²)</td><td>O(n + k)</td><td>稳定</td></tr><tr><td>基数排序</td><td>O(nk)</td><td>O(nk)</td><td>O(n + k)</td><td>稳定</td></tr></tbody></table><h2 id="什么是「稳定」的排序" tabindex="-1">什么是「稳定」的排序？ <a class="header-anchor" href="#什么是「稳定」的排序" aria-label="Permalink to “什么是「稳定」的排序？”">​</a></h2><p><strong>稳定性</strong>指的是排序后相同元素的相对顺序是否保持不变。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>不稳定排序示例:</span></span>
<span class="line"><span>原始: [2₁, 1, 2₂]</span></span>
<span class="line"><span>排序后: [1, 2₂, 2₁]  ← 2 的相对顺序变了！</span></span>
<span class="line"><span></span></span>
<span class="line"><span>稳定排序示例:</span></span>
<span class="line"><span>原始: [2₁, 1, 2₂]</span></span>
<span class="line"><span>排序后: [1, 2₁, 2₂]  ← 2 的相对顺序保持</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p><strong>什么时候需要稳定性？</strong></p><p>当排序的元素不只是数字，而是有多个属性时。</p><p>例如按成绩排序后，再按姓名排序——如果排序不稳定，姓名排序会打乱成绩排序的结果。</p><h2 id="如何选择排序算法" tabindex="-1">如何选择排序算法？ <a class="header-anchor" href="#如何选择排序算法" aria-label="Permalink to “如何选择排序算法？”">​</a></h2><h3 id="按数据量选择" tabindex="-1">按数据量选择 <a class="header-anchor" href="#按数据量选择" aria-label="Permalink to “按数据量选择”">​</a></h3><table tabindex="0"><thead><tr><th>数据量</th><th>推荐算法</th><th>原因</th></tr></thead><tbody><tr><td>n ≤ 50</td><td>插入排序</td><td>小数据量时常数小</td></tr><tr><td>n ≤ 10000</td><td>快速排序</td><td>综合性能最优</td></tr><tr><td>n 非常大</td><td>外部排序</td><td>内存装不下</td></tr></tbody></table><h3 id="按数据特点选择" tabindex="-1">按数据特点选择 <a class="header-anchor" href="#按数据特点选择" aria-label="Permalink to “按数据特点选择”">​</a></h3><table tabindex="0"><thead><tr><th>数据特点</th><th>推荐算法</th><th>原因</th></tr></thead><tbody><tr><td>基本有序</td><td>插入排序</td><td>有序时接近 O(n)</td></tr><tr><td>完全随机</td><td>快速排序</td><td>综合性能最优</td></tr><tr><td>有范围限制</td><td>计数/桶/基数</td><td>可达线性时间</td></tr><tr><td>需要稳定</td><td>归并排序</td><td>稳定的 O(n log n)</td></tr><tr><td>需要最坏情况</td><td>堆排序/归并排序</td><td>最坏也是 O(n log n)</td></tr></tbody></table><h3 id="按空间限制选择" tabindex="-1">按空间限制选择 <a class="header-anchor" href="#按空间限制选择" aria-label="Permalink to “按空间限制选择”">​</a></h3><table tabindex="0"><thead><tr><th>空间限制</th><th>推荐算法</th></tr></thead><tbody><tr><td>O(1)</td><td>堆排序、希尔排序、选择排序</td></tr><tr><td>O(log n)</td><td>快速排序（递归栈）</td></tr><tr><td>O(n)</td><td>归并排序、计数排序、桶排序、基数排序</td></tr></tbody></table><h2 id="排序算法的「三足鼎立」" tabindex="-1">排序算法的「三足鼎立」 <a class="header-anchor" href="#排序算法的「三足鼎立」" aria-label="Permalink to “排序算法的「三足鼎立」”">​</a></h2><p>在面试中最常被问到的三种排序算法是：<strong>快速排序、归并排序、堆排序</strong>。</p><h3 id="为什么是这三个" tabindex="-1">为什么是这三个？ <a class="header-anchor" href="#为什么是这三个" aria-label="Permalink to “为什么是这三个？”">​</a></h3><ol><li><strong>都是 O(n log n)</strong>：渐近时间复杂度最优</li><li><strong>各有特点</strong>：快速排序实际最快，归并排序稳定，堆排序最稳定（最坏情况）</li><li><strong>延伸问题多</strong>：partition、三路划分、Top K、手写堆……</li></ol><h2 id="各算法的特点" tabindex="-1">各算法的特点 <a class="header-anchor" href="#各算法的特点" aria-label="Permalink to “各算法的特点”">​</a></h2><h3 id="冒泡排序" tabindex="-1">冒泡排序 <a class="header-anchor" href="#冒泡排序" aria-label="Permalink to “冒泡排序”">​</a></h3><ul><li>最简单，但效率最低</li><li>适合教学，不适合实际使用</li><li>优化：提前终止 + 记录最后交换位置</li></ul><h3 id="选择排序" tabindex="-1">选择排序 <a class="header-anchor" href="#选择排序" aria-label="Permalink to “选择排序”">​</a></h3><ul><li>交换次数最少（最多 n 次）</li><li>但无论数据如何都是 O(n²)</li><li>不稳定</li></ul><h3 id="插入排序" tabindex="-1">插入排序 <a class="header-anchor" href="#插入排序" aria-label="Permalink to “插入排序”">​</a></h3><ul><li>小数据量和基本有序时效率高</li><li>实际排序中，经常在快速排序的递归到小数据量时切换到插入排序</li><li>稳定</li></ul><h3 id="希尔排序" tabindex="-1">希尔排序 <a class="header-anchor" href="#希尔排序" aria-label="Permalink to “希尔排序”">​</a></h3><ul><li>插入排序的改进版</li><li>通过「跳跃式」插入减少比较次数</li><li>不稳定</li></ul><h3 id="归并排序" tabindex="-1">归并排序 <a class="header-anchor" href="#归并排序" aria-label="Permalink to “归并排序”">​</a></h3><ul><li>稳定 + 最坏 O(n log n)</li><li>但需要额外 O(n) 空间</li><li>适合外部排序（磁盘文件分段读入）</li></ul><h3 id="快速排序" tabindex="-1">快速排序 <a class="header-anchor" href="#快速排序" aria-label="Permalink to “快速排序”">​</a></h3><ul><li>实际应用中最快</li><li>但最坏情况 O(n²) 需要优化（随机 pivot、三数取中等）</li><li>不稳定</li></ul><h3 id="堆排序" tabindex="-1">堆排序 <a class="header-anchor" href="#堆排序" aria-label="Permalink to “堆排序”">​</a></h3><ul><li>不需要递归，用数组直接实现</li><li>最坏情况也是 O(n log n)</li><li>不稳定</li></ul><h3 id="计数排序" tabindex="-1">计数排序 <a class="header-anchor" href="#计数排序" aria-label="Permalink to “计数排序”">​</a></h3><ul><li>适用于范围小的整数排序</li><li>时间 O(n)，但空间取决于数据范围</li><li>稳定</li></ul><h3 id="桶排序" tabindex="-1">桶排序 <a class="header-anchor" href="#桶排序" aria-label="Permalink to “桶排序”">​</a></h3><ul><li>适用于数据均匀分布</li><li>平均 O(n)，最坏 O(n²)</li><li>稳定</li></ul><h3 id="基数排序" tabindex="-1">基数排序 <a class="header-anchor" href="#基数排序" aria-label="Permalink to “基数排序”">​</a></h3><ul><li>适用于整数或字符串排序</li><li>按位稳定排序，k 为位数</li><li>稳定</li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>排序算法的选择取决于多种因素：</p><ol><li><strong>数据规模</strong>：小数据用插入排序，大数据用快速/归并/堆排序</li><li><strong>数据特点</strong>：基本有序用插入排序，有范围用计数/桶/基数</li><li><strong>稳定性要求</strong>：需要稳定用归并排序</li><li><strong>空间限制</strong>：空间紧张用堆排序/插入排序</li><li><strong>最坏情况</strong>：需要保证最坏性能用堆排序/归并排序</li></ol><p>没有最好的排序算法，只有最适合场景的排序算法。</p><h2 id="面试追问方向" tabindex="-1">面试追问方向 <a class="header-anchor" href="#面试追问方向" aria-label="Permalink to “面试追问方向”">​</a></h2><ul><li>什么是排序的稳定性？举例说明稳定和不稳定的排序</li><li>快速排序的最坏情况是什么？如何优化？</li><li>为什么说归并排序适合外部排序（磁盘排序）？</li><li>堆排序的空间复杂度是多少？它是原地排序吗？</li><li>计数排序、桶排序、基数排序的适用场景是什么？</li></ul>`,54)])])}const m=n(e,[["render",i]]);export{c as __pageData,m as default};
